import React, { useEffect, useRef } from 'react';
import { gsap } from 'gsap';

export default function Preloader({ onComplete }) {
  const containerRef = useRef(null);
  const pathRef = useRef(null);

  useEffect(() => {
    // Lock scrolling on mount
    document.body.style.overflow = 'hidden';

    const path = pathRef.current;
    if (!path) return;

    // Get exact length of the signature path
    const pathLength = path.getTotalLength();

    // Set initial dash styles to hide the line
    gsap.set(path, {
      strokeDasharray: pathLength,
      strokeDashoffset: pathLength
    });

    const tl = gsap.timeline({
      onComplete: () => {
        // Animate the entire preloader overlay out of view
        gsap.to(containerRef.current, {
          yPercent: -100,
          duration: 1.0,
          ease: 'power4.inOut',
          onComplete: () => {
            // Restore overflow scroll on document body
            document.body.style.overflow = '';
            if (onComplete) onComplete();
          }
        });
      }
    });

    // 1. Draw signature outline line
    tl.to(path, {
      strokeDashoffset: 0,
      duration: 2.4,
      ease: 'power2.inOut'
    });

    // 2. Fades out signature slightly before page slide transition
    tl.to(path, {
      opacity: 0,
      duration: 0.4,
      ease: 'power2.out'
    }, '+=0.2');

    return () => {
      document.body.style.overflow = '';
    };
  }, [onComplete]);

  return (
    <div
      ref={containerRef}
      className="fixed inset-0 z-[9999] bg-white bg-dotted flex flex-col items-center justify-center select-none"
    >
      <div className="flex flex-col items-center space-y-6">
        {/* Calligraphy Signature Drawing SVG */}
        <svg 
          viewBox="0 0 590 633" 
          fill="none" 
          xmlns="http://www.w3.org/2000/svg"
          className="w-48 h-48 md:w-64 md:h-64 text-[#121212]"
        >
          <path 
            ref={pathRef}
            d="M21.109 275.149C19.0554 277.86 20.4108 288.785 21.4478 302.133C22.6567 317.694 25.2162 333.923 30.6686 352.098C32.631 358.639 34.1083 364.111 36.1517 369.235C40.7246 380.702 60.0455 383.292 77.5012 385.695C105.717 389.579 123.666 388.098 143.905 389.802C157.139 390.917 166.895 388.118 170.314 383.682C178.044 373.655 179.894 352.611 185.039 336.809C189.554 322.939 188.807 306.035 191.21 287.563C193.664 268.692 188.848 254.633 183.724 250.536C165.225 235.744 180.593 338.072 181.63 349.377C182.93 363.556 188.109 378.446 192.226 395.203C196.124 411.066 205.174 446.708 217.147 487.082C226.031 517.042 232.631 550.867 236.04 575.541C237.442 585.685 236.738 602.7 235.383 612.783C234.028 622.867 231.317 625.577 226.193 626.974C213.983 630.302 203.223 627.693 195.389 622.939C167.016 605.721 164.205 582.575 159.06 568.867C153.7 554.584 155.292 534.685 155.272 483.796C155.26 454.143 166.874 432.743 174.76 410.071C179.749 395.73 192.175 378.61 201.457 360.435C209.468 344.75 220.967 327.229 226.111 314.219C234.967 291.823 240.846 248.616 242.55 225.965C246.047 179.49 234.028 157.477 225.474 125.02C220.693 106.874 211.479 87.6951 202.197 69.8492C194.323 54.712 186.137 37.7102 178.241 24.3103C173.833 16.8293 166.258 12.307 160.796 9.22655C158.231 7.78028 155.333 8.17921 152.92 9.19574C142.656 13.5198 134.14 45.596 129.612 69.726C122.321 108.576 130.608 169.675 139.49 191.536C150.607 218.899 162.767 231.941 173.035 249.068C184.405 268.033 193.571 287.347 203.162 306.918C210.04 320.955 218.215 337.373 224.735 349.377C226.422 352.483 228.483 355.856 229.869 355.23C264.629 339.523 233.987 255.352 237.745 244.376C238.461 242.285 242.16 243.646 245.251 247.384C261.356 266.861 265.448 284.678 271.29 295.644C276.743 305.878 279.844 316.18 282.924 317.258C310.435 326.888 288.079 269.748 289.434 258.792C289.895 255.066 293.5 255.968 295.236 257.673C302.996 265.296 305.165 281.228 317.805 307.904C320.784 314.191 322.949 318.193 325.013 319.271C327.077 320.349 329.11 318.316 331.513 314.558C348.49 288.004 350.344 246.48 355.139 237.506C362.444 223.835 372.236 260.034 378.756 270.662C381.797 275.618 387.309 280.591 392.772 285.725C395.147 287.957 398.235 287.471 403.358 280.016C434.47 234.751 440.005 201.958 445.837 193.364C454.508 180.586 472.165 208.037 499.488 216.59C526.433 225.025 567.206 215.635 583.09 211.148C596.364 207.398 548.97 230.627 530.477 239.519C511.326 248.727 475.204 262.047 433.731 281.228C395.972 298.691 363.446 305.255 344.707 310.358C315.244 318.382 286.148 329.2 265.633 334.663C231.127 343.85 186.877 359.306 163.578 363.783C143.23 367.693 105.595 380.499 78.3535 389.094C45.0563 399.599 30.1038 405.184 11.5905 412.371C7.41123 413.994 4.06401 415.452 4.01267 415.811C3.53858 419.13 15.5848 412.762 91.897 393.417C163.272 375.323 301.715 343.575 380.389 326.14C473.579 305.488 494.077 304.598 505.669 301.866C535.629 294.808 552.256 290.222 562.205 284.082C580.399 272.854 563.961 235.514 556.794 217.391C545.945 189.958 530.528 154.273 515.054 122.596C499.238 90.2192 479.886 53.6462 465.408 25.3577C461.64 17.9949 458.549 10.2739 454.452 6.14611C440.35 -8.06204 447.583 51.9417 446.895 86.237C446.302 115.783 447.562 170.004 449.267 210.47C452.031 276.102 456.475 308.623 457.491 325.329C459.949 365.72 466.702 392.698 470.501 412.351C472.673 423.586 474.957 434.591 476.662 446.235C478.85 461.185 480.42 474.965 482.823 486.63C483.172 492.093 484.527 497.596 486.92 503.059C487.957 505.811 488.634 508.522 489.333 515.422" 
            stroke="currentColor" 
            strokeWidth="8" 
            strokeLinecap="round" 
          />
        </svg>

        {/* Dynamic subtitle guide */}
        <div className="overflow-hidden h-4 flex items-center justify-center">
          <p className="text-[9px] font-black tracking-[0.3em] text-black/30 uppercase font-outfit animate-[pulse_1.5s_infinite]">
            Yogesh Shekhawat • Portfolio
          </p>
        </div>
      </div>
    </div>
  );
}
